import axios from 'axios';

const api = axios.create({
  baseURL: '/api',
  timeout: 15000,
});

export const employeeAPI = {
  list: (params) => api.get('/employees/', { params }),
  get: (id) => api.get(`/employees/${id}/`),
  create: (data) => api.post('/employees/', data, { headers: { 'Content-Type': 'multipart/form-data' } }),
  update: (id, data) => api.patch(`/employees/${id}/`, data),
  delete: (id) => api.delete(`/employees/${id}/`),
  // Face registration can take longer due to model initialization
  registerFace: (id, imageBase64) =>
    api.post(`/employees/${id}/register-face/`, { image: imageBase64 }, { timeout: 60000 }),
  stats: () => api.get('/employees/stats/'),
};

export const attendanceAPI = {
  todaySummary: () => api.get('/attendance/today-summary/'),
  liveFeed: () => api.get('/attendance/live-feed/'),
  list: (params) => api.get('/attendance/', { params }),
  exportExcel: (dateFrom, dateTo) =>
    api.get('/attendance/export-excel/', {
      params: { date_from: dateFrom, date_to: dateTo },
      responseType: 'blob',
    }),
  exportPDF: (dateFrom, dateTo) =>
    api.get('/attendance/export-pdf/', {
      params: { date_from: dateFrom, date_to: dateTo },
      responseType: 'blob',
    }),
};

export const cameraAPI = {
  list: () => api.get('/cameras/'),
  create: (data) => api.post('/cameras/', data),
  update: (id, data) => api.patch(`/cameras/${id}/`, data),
  delete: (id) => api.delete(`/cameras/${id}/`),
};

export const departmentAPI = {
  list: () => api.get('/departments/'),
  create: (data) => api.post('/departments/', data),
};

export default api;
